# ============================================================
#  DULCINEA.DM — Servidor independiente (Flask)
#  NO comparte código con el sistema de contratos/cotizaciones.
#  Usa la MISMA cuenta de servicio pero una HOJA DE CÁLCULO DISTINTA.
# ============================================================
import os, json, base64
from flask import Flask, request, jsonify, Response
from flask_cors import CORS

app = Flask(__name__)
CORS(app)

# ----- CONFIG: pega aquí el ID de tu hoja NUEVA de Dulcinea -----
SHEET_ID = os.environ.get("DULCINEA_SHEET_ID", "PEGAR_ID_DE_TU_HOJA_NUEVA")
CLAVE_MAESTRA = "91011"

# Pestañas propias de Dulcinea (no chocan con las del otro sistema)
WS_COT  = "DulcineaCotizaciones"
WS_CONF = "DulcineaConfig"

# ----- Credenciales de la cuenta de servicio (misma cuenta) -----
# Se leen desde variable de entorno SHEET_CREDENTIALS_JSON en Railway,
# o desde el archivo credenciales.json si está presente.
def _load_creds():
    raw = os.environ.get("SHEET_CREDENTIALS_JSON")
    if raw:
        return json.loads(raw)
    if os.path.exists("credenciales.json"):
        return json.load(open("credenciales.json"))
    raise RuntimeError("Faltan credenciales: define SHEET_CREDENTIALS_JSON")

_client = None
def get_sheets():
    global _client
    if _client:
        return _client
    from google.oauth2.service_account import Credentials
    import gspread
    scopes = ['https://spreadsheets.google.com/feeds',
              'https://www.googleapis.com/auth/drive']
    creds = Credentials.from_service_account_info(_load_creds(), scopes=scopes)
    _client = gspread.authorize(creds)
    return _client

def _open():
    return get_sheets().open_by_key(SHEET_ID)

def get_ws(nombre, cols=1):
    sh = _open()
    try:
        return sh.worksheet(nombre)
    except Exception:
        return sh.add_worksheet(title=nombre, rows=1000, cols=max(cols, 2))

# ---------- COTIZACIONES ----------
# Guardado simple: una fila por cotización -> [id, json]
def cot_ws():
    return get_ws(WS_COT, cols=2)

def cot_load_all():
    ws = cot_ws()
    rows = ws.get_all_values()
    out = []
    for r in rows:
        if len(r) >= 2 and r[1]:
            try:
                out.append(json.loads(r[1]))
            except Exception:
                pass
    return out

def cot_next_id():
    data = cot_load_all()
    ids = [int(c.get("id")) for c in data if str(c.get("id", "")).isdigit()]
    return (max(ids) + 1) if ids else 1

def cot_save(cot):
    ws = cot_ws()
    if not cot.get("id"):
        cot["id"] = cot_next_id()
    # buscar fila existente
    rows = ws.get_all_values()
    fila = None
    for i, r in enumerate(rows):
        if r and str(r[0]) == str(cot["id"]):
            fila = i + 1
            break
    payload = json.dumps(cot, ensure_ascii=False)
    if fila:
        ws.update(f"A{fila}:B{fila}", [[str(cot["id"]), payload]])
    else:
        ws.append_row([str(cot["id"]), payload])
    return cot

def cot_delete(cid):
    ws = cot_ws()
    rows = ws.get_all_values()
    for i, r in enumerate(rows):
        if r and str(r[0]) == str(cid):
            ws.delete_rows(i + 1)
            return True
    return False

# ---------- CONFIG (asesores + catálogo) ----------
# Pestaña DulcineaConfig: A=clave, B=json
def conf_ws():
    return get_ws(WS_CONF, cols=2)

def conf_read():
    ws = conf_ws()
    rows = ws.get_all_values()
    data = {}
    for r in rows:
        if len(r) >= 2 and r[0]:
            try:
                data[r[0]] = json.loads(r[1])
            except Exception:
                pass
    return data

def conf_write(key, value):
    ws = conf_ws()
    rows = ws.get_all_values()
    fila = None
    for i, r in enumerate(rows):
        if r and r[0] == key:
            fila = i + 1
            break
    payload = json.dumps(value, ensure_ascii=False)
    if fila:
        ws.update(f"A{fila}:B{fila}", [[key, payload]])
    else:
        ws.append_row([key, payload])

# ============================================================
#  RUTAS
# ============================================================
@app.route('/')
def home():
    return "Dulcinea.DM server OK"

@app.route('/dulcinea')
def dulcinea_page():
    # Sirve el HTML incrustado (sin caché, ver briefing error 15)
    content = base64.b64decode(HTML_B64).decode('utf-8')
    resp = Response(content, mimetype='text/html')
    resp.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, max-age=0'
    resp.headers['Pragma'] = 'no-cache'
    return resp

@app.route('/api/dulcinea/diag')
def diag():
    try:
        _open().title
        return jsonify(ok=True)
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500

@app.route('/api/dulcinea/config', methods=['GET'])
def get_config():
    try:
        c = conf_read()
        return jsonify(ok=True,
                       asesores=c.get("asesores", []),
                       catalogo=c.get("catalogo", {}))
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500

@app.route('/api/dulcinea/config/save', methods=['POST'])
def save_config():
    d = request.get_json(force=True)
    if str(d.get("clave")) != CLAVE_MAESTRA:
        return jsonify(ok=False, error="no autorizado"), 403
    try:
        if "asesores" in d:
            conf_write("asesores", d["asesores"])
        if "catalogo" in d:
            conf_write("catalogo", d["catalogo"])
        return jsonify(ok=True)
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500

@app.route('/api/dulcinea/cotizaciones', methods=['GET'])
def list_cot():
    try:
        return jsonify(ok=True, data=cot_load_all())
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500

@app.route('/api/dulcinea/cotizaciones', methods=['POST'])
def crear_cot():
    try:
        cot = request.get_json(force=True)
        cot["id"] = None
        return jsonify(ok=True, data=cot_save(cot))
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500

@app.route('/api/dulcinea/cotizaciones/<cid>', methods=['PUT'])
def actualizar_cot(cid):
    try:
        cot = request.get_json(force=True)
        cot["id"] = cid
        return jsonify(ok=True, data=cot_save(cot))
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500

@app.route('/api/dulcinea/cotizaciones/<cid>', methods=['DELETE'])
def borrar_cot(cid):
    d = request.get_json(force=True) if request.data else {}
    if str(d.get("clave")) != CLAVE_MAESTRA:
        return jsonify(ok=False, error="no autorizado"), 403
    try:
        return jsonify(ok=cot_delete(cid))
    except Exception as e:
        return jsonify(ok=False, error=str(e)), 500

# HTML incrustado en base64 (se rellena en build)
HTML_B64 = ""

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.environ.get("PORT", 5000)))
